import play.api.mvc._
import javax.inject.Inject
import scala.concurrent.{ExecutionContext, Future}
import play.api.libs.json.Json
import models.Order
import services.UserService
import repositories.OrdersRepository

class OrderController @Inject()(val ordersRepo: OrdersRepository,
                                val userService: UserService)(implicit ec: ExecutionContext)
  extends Controller {

  def getOrderDetails(orderId: Long): Action[AnyContent] = Action.async { implicit request =>
    val orderFuture = ordersRepo.findById(orderId).map {
      case Some(order) => Ok(Json.toJson(order))
      case None        => NotFound("Order not found")
